---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/registry/bejamas-maia/lib/utils";
import { cva } from "class-variance-authority";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  size?: "sm" | "default" | "lg";
  position?: "item-aligned" | "popper";
  align?: "start" | "center" | "end";
  alignOffset?: number;
  side?: "top" | "bottom";
  sideOffset?: number;
}

const {
  class: className = "",
  size = "default",
  position = "item-aligned",
  align = "center",
  alignOffset = 0,
  side = "bottom",
  sideOffset = 4,
  ...rest
} = Astro.props as Props;

const contentVariants = cva(
  [
    "group/select-content cn-menu-target focus-visible:outline-none z-50 relative overflow-hidden",
    "origin-(--transform-origin) duration-100",
    "data-open:animate-in data-closed:animate-out data-closed:fade-out-0 data-open:fade-in-0 data-closed:zoom-out-95 data-open:zoom-in-95",
    "data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2",
    "data-[align-trigger=true]:animate-none data-[align-trigger=true]:transition-none",
  ],
  {
    variants: {
      position: {
        "item-aligned": "",
        popper:
          "data-[side=bottom]:translate-y-1 data-[side=top]:-translate-y-1",
      },
      side: {
        top: "",
        bottom: "",
      },
    },
    defaultVariants: {
      position: "item-aligned",
      side: "bottom",
    },
  },
);
---

<div
  {...rest}
  hidden
  data-slot="select-content"
  data-size={size}
  data-position={position}
  data-align-trigger={position === "item-aligned"}
  data-align={align}
  data-align-offset={alignOffset}
  data-side={side}
  data-side-offset={sideOffset}
  class={cn(
    "cn-select-content",
    contentVariants({ position, side }),
    className,
  )}
>
  <div
    data-slot="select-scroll-up-button"
    class="cn-select-scroll-up-button"
    hidden
  >
    <slot name="scroll-up"
      ><SemanticIcon name="chevron-up" class="size-4" /></slot
    >
  </div>
  <div
    data-slot="select-viewport"
    data-position={position}
    class="cn-select-viewport max-h-[var(--select-content-available-height,300px)] overflow-x-hidden overflow-y-auto"
  >
    <slot />
  </div>
  <div
    data-slot="select-scroll-down-button"
    class="cn-select-scroll-down-button"
    hidden
  >
    <slot name="scroll-down"
      ><SemanticIcon name="chevron-down" class="size-4" /></slot
    >
  </div>
</div>

