import type { HTMLAttributes } from "astro/types";
import { cn } from "@/registry/bejamas-maia/lib/utils";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"button"> {
  class?: string;
  size?: "sm" | "default" | "lg";
}

const {
  class: className = "",
  size = "default",
  ...rest
} = Astro.props as Props;
---

<button
  {...rest}
  type="button"
  data-slot="select-trigger"
  data-size={size}
  class={cn(
    "cn-select-trigger",
    "flex w-full items-center justify-between whitespace-nowrap outline-none select-none transition-colors",
    "disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50",
    "*:data-[slot=select-value]:line-clamp-1",
    "[&_svg]:pointer-events-none [&_svg]:shrink-0",
    className,
  )}
>
  <slot />
  <SemanticIcon
    name="chevron-down"
    class="cn-select-icon cn-select-trigger-icon"
    data-slot="select-icon"
  />
</button>

